//mechaxil.com/collections/microcontrollers"},ESP32:{content:"<div>A low-cost, low-power system on a chip (SoC) with integrated Wi-Fi and dual-mode Bluetooth.</div>",link:"https://mechaxil.com/products/esp32-c3-devkitm-1"},"ESP32-C3":{content:"<div>A variant of the ESP32 microcontroller with a RISC-V core, designed for low-power applications with Wi-Fi and Bluetooth connectivity.</div>",link:"https://mechaxil.com/products/esp32-c3-devkitm-1"},"JST Connector":{content:"<div>Small standardized connectors used for power and signals in embedded systems. Common types include JST-XH and JST-SM.</div>"},"Li-ion Battery":{content:"<div>A rechargeable lithium-ion cell, known for high energy density and low self-discharge. Used in portable and solar-powered devices.</div>"},"MOSFET Module":{content:'\n        <div>Small logic-level power switch board that lets 3.3V logic control high-current DC loads like pumps or valves.</div>\n        <img src="https://mechaxil.com/cdn/shop/files/optocoupler_mosfet.webp?v=1758040365&width=1200"\n             alt="MOSFET Module"\n             style="max-width:100%;margin-top:0.5rem;" />',link:"https://mechaxil.com/products/mosfet-with-opto-module?variant=55421310828892"},MT3608:{content:'\n        <div>DC-DC boost converter that steps up voltages (e.g. 5V \u2192 12V) with adjustable output and high efficiency.</div>\n        <img src="https://mechaxil.com/cdn/shop/files/mt3608-module.jpg?v=1730892014&width=1200"\n             alt="MT3608 Step-Up Module"\n             style="max-width:100%;margin-top:0.5rem;" />',link:"https://mechaxil.com/products/module-step-up-mt3608"},PETG:{content:"<div>A durable and easy-to-print 3D printing filament known for its strength, flexibility, and resistance to impact and moisture.</div>",link:"https://mechaxil.com/collections/3d-printing-1?sort_by=best-selling&filter.v.t.shopify.filament-type=gid%3A%2F%2Fshopify%2FTaxonomyValue%2F963"},PLA:{content:"<div>A biodegradable and easy-to-print 3D printing filament made from renewable resources like corn starch or sugarcane.</div>",link:"https://mechaxil.com/collections/3d-printing-1?sort_by=best-selling&filter.v.t.shopify.filament-type=gid%3A%2F%2Fshopify%2FTaxonomyValue%2F19180"},"Proto Board":{content:"<div>A prototyping board with copper pads or holes for quickly assembling circuits before designing a custom PCB.</div>"},"Raspberry Pi Pico":{content:'\n        <div>A low-cost microcontroller board from Raspberry Pi, based on the RP2040 dual-core ARM Cortex-M0+ chip.</div>\n        <img src="https://mechaxil.com/cdn/shop/files/IMG_20250815_155310.jpg?v=1755350246&width=1200"\n             alt="Raspberry Pi Pico"\n             style="max-width:100%;margin-top:0.5rem;" />',link:"https://mechaxil.com/products/mcu-rpi-pico?variant=55267271606620"},"USB-C":{content:"<div>Reversible 24-pin USB connector supporting higher current and voltage ratings, ideal for powering embedded devices safely.</div>"},"Waveshare Solar Power Manager":{content:'\n        <div>The Waveshare Solar Power Manager handles Li-ion charging, status LEDs, and step-down rails.</div>\n        <img src="https://mechaxil.com/cdn/shop/files/IMG_20250815_154927.jpg?v=1755350653&width=1200"\n             alt="Waveshare Solar Module"\n             style="max-width:100%;margin-top:0.5rem;" />',link:"https://mechaxil.com/products/sensor-solar-manager-d-ws?variant=55265966195036"},WS2812:{content:'\n        <div>An addressable RGB LED with integrated control logic. Uses a single data line and supports chaining multiple LEDs.</div>\n        <img src="https://mechaxil.com/cdn/shop/files/ws2812-led.jpg?v=1730892015&width=1200"\n             alt="WS2812 RGB LED"\n             style="max-width:100%;margin-top:0.5rem;" />'},ADC:{content:"<div><b>Analog-to-Digital Converter</b> \u2014 converts analog voltages (like sensor outputs) into digital values that microcontrollers can read.</div>"},"ADC Calibration":{content:"<div>Mapping raw ADC readings to meaningful physical values, compensating for sensor tolerance and noise.</div>"},BOM:{content:"<div>A Bill of Materials (BOM) is a comprehensive list of parts, items, assemblies, and other materials required to create a product.</div>"},DC:{content:"<div><b>Direct Current</b> \u2014 electric current flowing in one direction, commonly used in batteries and electronic devices.</div>"},"DC-DC Converter":{content:"<div>Converts one DC voltage level to another, e.g. stepping up 5V to 12V for pumps or valves.</div>"},"FDM 3D Printing":{content:"<div>Fused Deposition Modeling (FDM) is a 3D printing technique that builds objects layer by layer by extruding melted thermoplastic filament through a heated nozzle.</div>",link:"https://mechaxil.com/collections/3d-printing-1"},"Flyback Diode":{content:"<div>A diode placed across inductive loads (like valves or pumps) to absorb voltage spikes when the current stops suddenly.</div>"},"I\xb2C":{content:"<div><b>Inter-Integrated Circuit</b> \u2014 two-wire communication protocol (SDA, SCL) for connecting sensors and peripherals with minimal pins.</div>"},LED:{content:"<div>A light-emitting diode that emits light when an electric current passes through it. Commonly used as indicators in electronic devices.</div>"},"Li-ion Charging":{content:"<div>The process of charging lithium-ion batteries, which involves applying a controlled voltage and current to safely replenish the battery's energy.</div>"},MicroPython:{content:"<div>A compact version of Python designed for microcontrollers like the ESP32 and Raspberry Pi Pico. Allows scripting directly on embedded hardware.</div>"},MOSFET:{content:"<div><b>Metal-Oxide-Semiconductor Field-Effect Transistor</b> \u2014 acts as an electronic power switch. Logic-level MOSFETs can be directly controlled from GPIO pins.</div>"},PCB:{content:"<div><b>Printed Circuit Board</b> \u2014 supports and connects electronic components using copper traces on an insulating substrate.</div>"},REPL:{content:"<div><b>Read-Eval-Print Loop</b> \u2014 an interactive programming environment that takes user inputs, executes them, and returns the results. Common in MicroPython for testing code snippets.</div>"},PWM:{content:"<div><b>Pulse Width Modulation</b> \u2014 controls average power to a load by switching rapidly. Duty cycle defines effective voltage or brightness.</div>"},"PWM Soft-Start":{content:"<div>Gradually increases PWM duty cycle when turning on motors or valves to reduce inrush current and extend lifespan.</div>"},"RGB LED":{content:"<div>A light-emitting diode that can produce a wide range of colors by combining red, green, and blue light.</div>"},"Tooltips with links":{content:'<div>Small pop-up boxes that provide additional information when hovering over or clicking on an element.</div> \n      <img src="img/mechaxil_robot.png" style="max-width:100%;margin-top:.5rem;" alt="Mechaxil robot" >',link:"https://mechaxil.com"},"Tooltips without links":{content:'<div>Small pop-up boxes that provide additional information when hovering over or clicking on an element.</div> \n      <img src="img/mechaxil_robot.png" style="max-width:100%;margin-top:.5rem;" alt="Mechaxil robot" >'},UART:{content:"<div><b>Universal Asynchronous Receiver-Transmitter</b> \u2014 simple serial interface for communication between MCUs or computers.</div>"}}}}]);